import { Board } from "../board/board";
import { Piece, PieceUtils } from "../board/piece";
import { MoveGenerator } from "./move_generator";

export type Move = number;
// 0000 000000 000000
// flag target source

export enum MoveFlag {
    Quiet = 0,
    DoublePawnPush = 1,
    KingCastle = 2,
    QueenCastle = 3,
    Capture = 4,
    EnPassant = 5,
    PromotionToKnight = 8,
    PromotionToBishop = 9,
    PromotionToRook = 10,
    PromotionToQueen = 11,
    PromotionToKnightCapture = 12,
    PromotionToBishopCapture = 13,
    PromotionToRookCapture = 14,
    PromotionToQueenCapture = 15,
}

export namespace MoveUtils { 
    const FLAG_MASK = 0b1111_0000_0000_0000;
    const TARGET_MASK = 0b0000_111111_000000;
    const SOURCE_MASK = 0b0000_000000_111111;

    export function encode(source: number, target: number, flag: number = 0) : Move {
        return ((flag << 12) | (target << 6) | source) as Move;
    }

    export function getSourceSquare(move: Move) : number {
        return (move & SOURCE_MASK);
    }

    export function getTargetSquare(move: Move) : number {
        return (move & TARGET_MASK) >> 6;
    }

    export function getMoveFlag(move: Move) : number {
        return (move & FLAG_MASK) >> 12;
    }

    export function isPromotion(move: Move) : boolean {
        const flag = getMoveFlag(move);
        return flag >= MoveFlag.PromotionToKnight && flag <= MoveFlag.PromotionToQueenCapture;
    }

    export function isCapture(move: Move) : boolean {
        const flag = getMoveFlag(move);
        return flag === MoveFlag.Capture || flag === MoveFlag.EnPassant || flag >= MoveFlag.PromotionToKnightCapture;
    }

    export function getPromotionPieceType(move: Move) : number {
        const flag = getMoveFlag(move);
        switch (flag) {
            case MoveFlag.PromotionToKnight:
            case MoveFlag.PromotionToKnightCapture:
                return Piece.Knight;
            case MoveFlag.PromotionToBishop:
            case MoveFlag.PromotionToBishopCapture:
                return Piece.Bishop;
            case MoveFlag.PromotionToRook:
            case MoveFlag.PromotionToRookCapture:
                return Piece.Rook;
            case MoveFlag.PromotionToQueen:
            case MoveFlag.PromotionToQueenCapture:
                return Piece.Queen;
            default:
                return Piece.None;
        }
    }
    

    export function moveToString(move: Move) : string {
        const source = getSourceSquare(move);
        const target = getTargetSquare(move);
        let moveStr = squareToString(source) + squareToString(target);
        if (isPromotion(move)) {
            const promoType = getPromotionPieceType(move);
            moveStr += PieceUtils.pieceTypeToChar(promoType).toLowerCase();
        }
        return moveStr;
    }

    export function moveToSAN(move: Move, board: Board, moveGenerator: MoveGenerator): string {
        const source = MoveUtils.getSourceSquare(move);
        const target = MoveUtils.getTargetSquare(move);
        const flag = MoveUtils.getMoveFlag(move);

        const movingPiece = board.getPieceOnSquare(source);
        const pieceType = PieceUtils.getType(movingPiece);

        if (flag === MoveFlag.KingCastle) return "O-O";
        if (flag === MoveFlag.QueenCastle) return "O-O-O";

        const isCapture =
            flag === MoveFlag.Capture ||
            flag === MoveFlag.EnPassant ||
            flag >= MoveFlag.PromotionToKnightCapture;

        let san = "";

        if (pieceType !== Piece.Pawn) {
            san += PieceUtils.pieceTypeToChar(pieceType);

            const legalMoves = moveGenerator.generateLegalMoves(board.sideToMove);

            const ambiguousMoves = legalMoves.filter(m => {
                if (m === move) return false;

                const sameTarget =
                    MoveUtils.getTargetSquare(m) === target;

                if (!sameTarget) return false;

                const otherSource = MoveUtils.getSourceSquare(m);
                const otherPiece = board.getPieceOnSquare(otherSource);

                return PieceUtils.getType(otherPiece) === pieceType;
            });

            if (ambiguousMoves.length > 0) {
                const sourceFile = source & 7;
                const sourceRank = source >> 3;

                const needFile = ambiguousMoves.some(m =>
                    (MoveUtils.getSourceSquare(m) & 7) === sourceFile
                );

                const needRank = ambiguousMoves.some(m =>
                    (MoveUtils.getSourceSquare(m) >> 3) === sourceRank
                );

                if (!needFile) {
                    san += squareToString(source)[0];
                } else if (!needRank) {
                    san += squareToString(source)[1];
                } else {
                    san += squareToString(source);
                }
            }
        }

        if (pieceType === Piece.Pawn && isCapture) {
            san += squareToString(source)[0];
        }

        if (isCapture) {
            san += "x";
        }

        san += squareToString(target);

        if (MoveUtils.isPromotion(move)) {
            san += "=" + PieceUtils.pieceTypeToChar(
                MoveUtils.getPromotionPieceType(move)
            );
        }

        board.makeMove(move);

        const opponent = board.sideToMove;
        const legalAfter = moveGenerator.generateLegalMoves(opponent);
        const inCheck = moveGenerator.isKingInCheck(opponent);

        if (inCheck && legalAfter.length === 0) {
            san += "#";
        } else if (inCheck) {
            san += "+";
        }

        board.unmakeMove(move);

        return san;
    }

    export function generatePGN(moves: Move[], initialFen: string): string {
        let pgn = "";
        const board = new Board();
        board.loadPositionFromFen(initialFen);
        const moveGenerator = new MoveGenerator(board);
        
        for (let i = 0; i < moves.length; i++) {
            const move = moves[i]!;
            if (i % 2 === 0) {
                pgn += ((i / 2) + 1).toString() + ". ";
            }
            pgn += MoveUtils.moveToSAN(move, board, moveGenerator) + " ";
            
            board.makeMove(move);
        }

        return pgn;
    }
}

export function squareToString(square: number): string {
    const file = square & 7;
    const rank = square >> 3;
    return String.fromCharCode('a'.charCodeAt(0) + file) + (rank+1).toString();
}

export function stringToSquare(squareStr: string): number {
    //if (squareStr.length !== 2) throw new Error("Invalid square string");
    const file = squareStr.charCodeAt(0) - 'a'.charCodeAt(0);
    const rank = parseInt(squareStr[1]!) - 1;
    return rank * 8 + file;
}


